export type EvidenceLabel = 'Established Fact' | 'Strong Evidence' | 'Theoretical Interpretation';

export interface KeyClaim {
  text: string;
  label: EvidenceLabel;
}

export interface ExpertAnalysis {
  field: string;
  technicalAnalysis: string;
  plainLanguage: string;
  keyClaims: KeyClaim[];
}

export interface Disagreement {
  description: string;
  evidenceStrength: number; // 1-10
  realWorldImpact: number; // 1-10
  riskIfIncorrect: number; // 1-10
}

export interface Debate {
  agreements: string[];
  conflicts: Disagreement[];
  resolution: string;
  uncertainty: string;
}

export interface FinalVerdict {
  coreConclusion: string;
  supportingEvidenceSummary: string;
  economicFeasibility: string;
  ethicalGovernance: string;
  risksTradeOffs: string;
  confidenceLevel: number; // 0-100
  failureConditions: string;
}

export interface RoundtableResponse {
  intent: string[];
  experts: ExpertAnalysis[];
  debate: Debate;
  verdict: FinalVerdict;
}

export enum ExpertField {
  Physics = "Physics",
  Biology = "Biology",
  Medicine = "Medicine",
  Psychology = "Psychology",
  Psychotherapy = "Psychotherapy",
  Chemistry = "Chemistry",
  Mathematics = "Mathematics",
  ComputerScience = "Computer Science",
  Robotics = "Robotics & Automation",
  MusicScience = "Music & Sound Science",
  SystemsScience = "Systems Science",
  Economics = "Economics & Incentive Systems",
  Ethics = "Ethics & Governance",
  Anthropology = "Anthropology & Sociology"
}

import { GoogleGenAI, Type } from "@google/genai";
import { RoundtableResponse } from "../types";
import { SYSTEM_PROMPT } from "../constants";

export const generateRoundtableAnalysis = async (userInput: string): Promise<RoundtableResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userInput,
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          intent: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          experts: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                field: { type: Type.STRING },
                technicalAnalysis: { type: Type.STRING },
                plainLanguage: { type: Type.STRING },
                keyClaims: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      text: { type: Type.STRING },
                      label: { type: Type.STRING, description: "Must be 'Established Fact', 'Strong Evidence', or 'Theoretical Interpretation'" }
                    },
                    required: ["text", "label"]
                  }
                }
              },
              required: ["field", "technicalAnalysis", "plainLanguage", "keyClaims"]
            }
          },
          debate: {
            type: Type.OBJECT,
            properties: {
              agreements: { type: Type.ARRAY, items: { type: Type.STRING } },
              conflicts: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    description: { type: Type.STRING },
                    evidenceStrength: { type: Type.NUMBER },
                    realWorldImpact: { type: Type.NUMBER },
                    riskIfIncorrect: { type: Type.NUMBER }
                  },
                  required: ["description", "evidenceStrength", "realWorldImpact", "riskIfIncorrect"]
                }
              },
              resolution: { type: Type.STRING },
              uncertainty: { type: Type.STRING }
            },
            required: ["agreements", "conflicts", "resolution", "uncertainty"]
          },
          verdict: {
            type: Type.OBJECT,
            properties: {
              coreConclusion: { type: Type.STRING },
              supportingEvidenceSummary: { type: Type.STRING },
              economicFeasibility: { type: Type.STRING },
              ethicalGovernance: { type: Type.STRING },
              risksTradeOffs: { type: Type.STRING },
              confidenceLevel: { type: Type.NUMBER },
              failureConditions: { type: Type.STRING }
            },
            required: ["coreConclusion", "supportingEvidenceSummary", "economicFeasibility", "ethicalGovernance", "risksTradeOffs", "confidenceLevel", "failureConditions"]
          }
        },
        required: ["intent", "experts", "debate", "verdict"]
      }
    }
  });

  const jsonStr = response.text.trim();
  try {
    return JSON.parse(jsonStr) as RoundtableResponse;
  } catch (error) {
    console.error("Failed to parse Gemini response:", jsonStr);
    throw new Error("Invalid response format from AI");
  }
};

